body.prompt:
=Score the following keyword for SEO potential on a blog about {{ $json.domain }}.

Keyword: {{ $json.keyword }}

Consider: search intent, competition level (lower is better for new sites), content depth possible, monetization potential.

Return ONLY a JSON object: {"score": <0-100>, "reasoning": "<2 sentences>", "recommended_title": "<suggested post title>"}

parameters.jsCode:
const items = $input.all();

// Parse LLM response and attach score to each keyword
const scored = items.map(item => {
  try {
    const parsed = JSON.parse(item.json.text);
    return {
      json: {
        ...item.json,
        llm_score: parsed.score || 0,
        llm_reasoning: parsed.reasoning || '',
        recommended_title: parsed.recommended_title || ''
      }
    };
  } catch(e) {
    return { json: { ...item.json, llm_score: 0, llm_reasoning: 'parse error', recommended_title: '' } };
  }
});

// Sort by score descending, take top 3
scored.sort((a, b) => b.json.llm_score - a.json.llm_score);
return scored.slice(0, 3);
